#include<bits/stdc++.h>
using namespace std;
int a[100010];
int n,m;
vector<int> mp[100010],mp1[100010];
int in[100010];
int cnt=0;
bool flag[100010];
int dfn[100010],f[100010],low[100010],scccnt,scc[100010],siz[100010],val[100010],dfncnt;
void tarjan(int x,int fa)
{
    int soncnt=0;
    dfn[x]=low[x]=++dfncnt;
    for(int v:mp[x])
    {
        if(!dfn[v])
        {
            soncnt++;
            tarjan(v,x);
            low[x]=min(low[x],low[v]);
            if(x!=fa&&dfn[x]<=low[v]&&!flag[x])
            {
                flag[x]=1;
                cnt++;
            }
        }
        else
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(soncnt>=2&&x==fa&&!flag[x])
    {
        flag[x]=1;
        cnt++;
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i,i);
        }
    }
    printf("%d\n",cnt);
    for(int i=1;i<=n;i++)if(flag[i])
    {
        printf("%d ",i);
    }
    return 0;
}
